```class Solution {
    public long validSubstringCount(String word1, String word2) {
        int count = 0;
        int word2Len = word2.length();
        int word1Len = word1.length();
        int[] word1Count = new int[26];
        int[] word2Count = new int[26];
        for (int i = 0; i < word2Len; i++) {
            word2Count[word2.charAt(i) - 'a']++;
        }
        for (int i = 0; i < word1Len; i++) {
            word1Count[word1.charAt(i) - 'a']++;
            if (i >= word2Len) {
                word1Count[word1.charAt(i - word2Len) - 'a']--;
            }
            if (Arrays.equals(word1Count, word2Count)) {
                count++;
            }
        }
        return count;
    }
}```
